example.code:
//При помощи данного сервиса можно управлять запущенным процессом массового импорта

//Чтобы отправить команду процессу импорта используйте ExecuteCommand(workUid, command), где
//Guid workUid - уникальный идентификатор процесса массового импорта;
//ImportCommand command - выполняемая команда;
PublicAPI.Services.BulkDataImportCommand.SetCommand(workUid, command);

//Чтобы получить информацию по запущенному импорту GetCommand(workUid), где
//Guid workUid - уникальный идентификатор процесса массового импорта;
//Возвращает сохранённую команду ImportCommand? - null, если нет сохранённой команды.
PublicAPI.Services.BulkDataImport.GetCommand(workUid);

//Чтоб удалить текущую сохранённую команду, используйте метод Reset(workUid), где
//Guid workUid - уникальный идентификатор процесса массового импорта;
PublicAPI.Services.BulkDataImport.Reset(workUid);

//При помощи данного сервиса осуществляется массовый импорт объектов в систему

//Чтобы импортировать объекты в основную базу данных используйте Import(dataSource, mapBuilder), где
//IDataSource dataSource - источник данных;
//IDataSource - Источник данных.
//MapBuilderBase mapBuilder - маппинг объектов;
PublicAPI.Services.BulkDataImport.Import(dataSource, mapBuilder);

//Чтобы получить информацию по запущенному импорту используйте GetImportProgressInfo(workUid), где
//Guid workUid - уникальный идентификатор работы;
PublicAPI.Services.BulkDataImport.GetImportProgressInfo(workUid);

member.example:

var partName = "SmartLogger";
var action = "Example";
var description = "демо SmartLogger";
var logKey = new Guid("{49609953-1B6A-424F-91F7-F27044151117}");
using (var logger = new SmartLogger(partName, action, description, logKey))
{
    logger.Info("приостановка потока на 1 секунду");
    var date = DateTime.Now;
    System.Threading.Thread.Sleep(1000);
    logger.Info("продолжили выполнение потока", date);
    logger.Error(new Exception("вывели исключение 1"));

    var innerAction = "InnerExample";
    var innerDescription = "демо вложенного SmartLogger";
    using (var innerLogger = logger.InnerLogger(innerAction, innerDescription))
    {
        date = DateTime.Now;
        System.Threading.Thread.Sleep(2000);
        innerLogger.Info("выполнили действие после паузы в 2 секунды внутри innerLogger", date);
        innerLogger.Error(new Exception("вывели исключение 2"));
    }
}

Данный код выводит в лог информацию вида:

INFO  2019-04-11 12:18:19,800 - SmartLogger(49609953-1b6a-424f-91f7-f27044151117) : Example => Start (демо SmartLogger)
INFO  2019-04-11 12:18:19,800 - SmartLogger(49609953-1b6a-424f-91f7-f27044151117) :   Example ... приостановка потока на 1 секунду
INFO  2019-04-11 12:18:20,802 - SmartLogger(49609953-1b6a-424f-91f7-f27044151117) :   Example ... продолжили выполнение потока (время выполнения: 00:00:01.0005715)
ERROR 2019-04-11 12:18:20,802 - SmartLogger(49609953-1b6a-424f-91f7-f27044151117) :   Example => Error
System.Exception: вывели исключение 1
INFO  2019-04-11 12:18:20,803 - SmartLogger (49609953-1b6a-424f-91f7-f27044151117):   InnerExample => Start(демо вложенного SmartLogger)
INFO  2019-04-11 12:18:22,804 - SmartLogger(49609953-1b6a-424f-91f7-f27044151117) :     InnerExample ... выполнили действие после паузы в 2 секунды внутри innerLogger (время выполнения: 00:00:02.0009864)
ERROR 2019-04-11 12:18:22,804 - SmartLogger(49609953-1b6a-424f-91f7-f27044151117) :     InnerExample => Error
System.Exception: вывели исключение 2
INFO  2019-04-11 12:18:22,806 - SmartLogger (49609953-1b6a-424f-91f7-f27044151117):   InnerExample => End (время выполнения: 00:00:02.0019868)
INFO  2019-04-11 12:18:22,806 - SmartLogger(49609953-1b6a-424f-91f7-f27044151117) : Example => End (время выполнения: 00:00:03.0055522)

example.code:
//С помощью данного сервиса мы можем управлять списками наблюдателей:
//получать списки наблюдателей, очищать списки наблюдателей и создавать наблюдателей

//Чтобы получить список наблюдателей, используйте функцию GetWatches(objectUid, actionUid, entity), где:
//Guid objectUid - идентификатор типа сущности;
//Guid actionUid - идентификатор действия;
//IEntity entity - сущность
var userList = Locator.GetServiceNotNull<IWatchEntityService>().GetWatches(objectUid, actionUid, entity);

//Чтобы очистить список наблюдателей для определённого объекта используйте функцию ClearForObject(objectUid, entityId).
//Чтобы очистить список наблюдателей для типа объекта вместо entityId передавайте значение null.
Locator.GetServiceNotNull<IWatchEntityService>().ClearForObject(objectUid, entityId)

//Чтобы добавить пользователя в список наблюдателей используйте функцию CreateWatchByUser(typeUid, entityId, user), где
//Guid typeUid - идентификатор типа сущности;
//long? entityId - идентификатор сущности;
//IUser user - пользователь.
Locator.GetServiceNotNull<IWatchEntityService>().CreateWatchByUser(typeUid, entityId, user);

